// src/pages/MasterData/MasterData.jsx

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

const MasterData = () => {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    id: '',
    image: '',
    gate: '',
    note: '',
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newTruck = {
      id: parseInt(form.id),
      image: form.image,
      gate: form.gate,
      note: form.note,
    };

    try {
      const res = await fetch('http://localhost:5000/api/trucks', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTruck),
      });

      const data = await res.json();
      if (res.ok) {
        alert('Truck berhasil disimpan!');
        navigate('/tracking');
      } else {
        alert(data.message);
      }
    } catch (err) {
      alert('Gagal terhubung ke server');
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar */}
      <div className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img
              src="https://via.placeholder.com/50"
              alt="Admin Icon"
              className="rounded-full mb-2"
            />
            <h2 className="font-semibold text-lg">Admin</h2>
          </div>

          <div className="space-y-6">
            <div className="bg-gray-700 rounded-lg p-3 text-center">
              <Link to="/master-data" className="block hover:text-white">Master Data</Link>
            </div>
            <div className="bg-gray-700 rounded-lg p-3 text-center">
              <Link to="/tracking" className="block hover:text-white">Tracking</Link>
            </div>
            <div className="bg-gray-700 rounded-lg p-3 text-center">
              <Link to="/info-driver" className="block hover:text-white">Info Driver</Link>
            </div>
          </div>
        </div>

        <div className="space-y-6 mt-6">
          <div className="bg-gray-700 rounded-lg p-3 text-center">
            <Link to="/settings" className="block hover:text-white">Settings</Link>
          </div>
          <div className="bg-gray-700 rounded-lg p-3 text-center">
            <Link to="/logout" className="block hover:text-white">Logout</Link>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-4">
            <h1 className="text-2xl font-bold">Dashboard</h1>
            <span className="text-lg font-medium text-gray-600">/ Truck</span>
          </div>
        </div>

        {/* Form Tambah Truck */}
        <form onSubmit={handleSubmit} className="mb-6 bg-white p-6 rounded-lg shadow-md space-y-4">
          <h2 className="text-xl font-semibold mb-2">Tambah Truck Baru</h2>

          <div>
            <label className="block text-sm font-medium text-gray-700">Truck ID</label>
            <input
              type="number"
              name="id"
              value={form.id}
              onChange={handleChange}
              required
              className="mt-1 p-2 border border-gray-300 rounded w-full"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Image URL</label>
            <input
              type="text"
              name="image"
              value={form.image}
              onChange={handleChange}
              required
              className="mt-1 p-2 border border-gray-300 rounded w-full"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Gate</label>
            <input
              type="text"
              name="gate"
              value={form.gate}
              onChange={handleChange}
              required
              className="mt-1 p-2 border border-gray-300 rounded w-full"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Note</label>
            <input
              type="text"
              name="note"
              value={form.note}
              onChange={handleChange}
              className="mt-1 p-2 border border-gray-300 rounded w-full"
            />
          </div>

          <button type="submit" className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600">
            Simpan Truck
          </button>
        </form>

        {/* Placeholder untuk table (nanti bisa fetch data juga dari backend) */}
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white rounded-lg shadow-md">
            <thead>
              <tr className="bg-gray-200 text-gray-600 text-left">
                <th className="py-3 px-4">Truck ID</th>
                <th className="py-3 px-4">Gate</th>
                <th className="py-3 px-4">Note</th>
                <th className="py-3 px-4">Gambar</th>
              </tr>
            </thead>
            <tbody>
              {/* Nanti fetch data dari backend */}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default MasterData;
